'use client';

import React, { useState, useEffect } from 'react';
import { 
  TrendingUp, TrendingDown, Shield, AlertTriangle, 
  Target, Activity, Clock, CheckCircle, XCircle,
  BarChart3, PieChart, LineChart, Calendar
} from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

interface AnalyticsData {
  overview: {
    totalTargets: number;
    totalScans: number;
    totalVulnerabilities: number;
    activeScans: number;
    criticalVulns: number;
    highVulns: number;
    mediumVulns: number;
    lowVulns: number;
  };
  trends: {
    scansThisWeek: number;
    scansLastWeek: number;
    vulnsThisWeek: number;
    vulnsLastWeek: number;
  };
  topTargets: Array<{
    id: string;
    name: string;
    vulnerabilityCount: number;
    criticalCount: number;
    lastScan: string;
  }>;
  recentActivity: Array<{
    type: string;
    message: string;
    timestamp: string;
  }>;
}

export default function AnalyticsPage() {
  const router = useRouter();
  const [data, setData] = useState<AnalyticsData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [timeRange, setTimeRange] = useState<'7d' | '30d' | '90d'>('7d');

  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
      return;
    }
    fetchAnalytics();
  }, [router, timeRange]);

  const fetchAnalytics = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/analytics/dashboard?days=${timeRange === '7d' ? 7 : timeRange === '30d' ? 30 : 90}`, {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      if (!response.ok) throw new Error('Failed to fetch analytics');

      const analyticsData = await response.json();
      setData(analyticsData);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className=\"flex items-center justify-center min-h-screen bg-[#050812]\">
        <div className=\"text-center\">
          <div className=\"w-16 h-16 border-4 border-cyber-green border-t-transparent rounded-full animate-spin mx-auto mb-4\"></div>
          <p className=\"text-cyber-green font-mono text-sm\">Loading Analytics...</p>
        </div>
      </div>
    );
  }

  if (error || !data) {
    return (
      <div className=\"flex items-center justify-center min-h-screen bg-[#050812] p-6\">
        <div className=\"bg-[#0b1120] border border-cyber-pink/20 rounded-sm p-6 max-w-md\">
          <h3 className=\"text-white font-heading font-bold text-lg mb-4\">Error Loading Analytics</h3>
          <p className=\"text-cyber-muted font-mono text-sm mb-4\">{error}</p>
          <button 
            onClick={fetchAnalytics}
            className=\"w-full bg-cyber-green text-black font-heading font-bold text-xs uppercase py-2 rounded-sm\"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  const { overview, trends, topTargets, recentActivity } = data;

  const scansTrend = trends.scansThisWeek - trends.scansLastWeek;
  const vulnsTrend = trends.vulnsThisWeek - trends.vulnsLastWeek;
  const scansPercentChange = trends.scansLastWeek > 0 ? ((scansTrend / trends.scansLastWeek) * 100).toFixed(1) : '0';
  const vulnsPercentChange = trends.vulnsLastWeek > 0 ? ((vulnsTrend / trends.vulnsLastWeek) * 100).toFixed(1) : '0';

  return (
    <div className=\"min-h-screen bg-[#050812] text-white p-6\">
      {/* Header */}
      <div className=\"mb-8\">
        <div className=\"flex justify-between items-center mb-4\">
          <div>
            <h1 className=\"text-3xl font-heading font-bold text-white mb-2\">
              Analytics Dashboard
            </h1>
            <p className=\"text-cyber-muted font-mono text-sm\">
              Comprehensive security metrics and insights
            </p>
          </div>

          <div className=\"flex gap-3\">
            <select
              value={timeRange}
              onChange={(e) => setTimeRange(e.target.value as any)}
              className=\"bg-[#0b1120] border border-white/10 text-white font-mono text-xs px-4 py-2 rounded-sm focus:border-cyber-green outline-none\"
            >
              <option value=\"7d\">Last 7 Days</option>
              <option value=\"30d\">Last 30 Days</option>
              <option value=\"90d\">Last 90 Days</option>
            </select>

            <Link
              href=\"/dashboard\"
              className=\"px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors\"
            >
              Back to Dashboard
            </Link>
          </div>
        </div>
      </div>

      {/* Overview Stats */}
      <div className=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6\">
        <div className=\"bg-[#0b1120] border border-white/5 p-6 rounded-sm\">
          <div className=\"flex justify-between items-start mb-4\">
            <div>
              <p className=\"text-cyber-muted font-mono text-xs uppercase mb-1\">Total Targets</p>
              <p className=\"text-3xl font-heading font-bold text-white\">{overview.totalTargets}</p>
            </div>
            <div className=\"p-3 bg-cyber-blue/10 rounded-sm\">
              <Target className=\"w-6 h-6 text-cyber-blue\" />
            </div>
          </div>
          <div className=\"flex items-center gap-2 text-xs font-mono\">
            <span className=\"text-cyber-green\">Active monitoring</span>
          </div>
        </div>

        <div className=\"bg-[#0b1120] border border-white/5 p-6 rounded-sm\">
          <div className=\"flex justify-between items-start mb-4\">
            <div>
              <p className=\"text-cyber-muted font-mono text-xs uppercase mb-1\">Total Scans</p>
              <p className=\"text-3xl font-heading font-bold text-white\">{overview.totalScans}</p>
            </div>
            <div className=\"p-3 bg-cyber-green/10 rounded-sm\">
              <Activity className=\"w-6 h-6 text-cyber-green\" />
            </div>
          </div>
          <div className=\"flex items-center gap-2 text-xs font-mono\">
            {scansTrend >= 0 ? (
              <>
                <TrendingUp className=\"w-4 h-4 text-cyber-green\" />
                <span className=\"text-cyber-green\">+{scansPercentChange}% this week</span>
              </>
            ) : (
              <>
                <TrendingDown className=\"w-4 h-4 text-cyber-pink\" />
                <span className=\"text-cyber-pink\">{scansPercentChange}% this week</span>
              </>
            )}
          </div>
        </div>

        <div className=\"bg-[#0b1120] border border-white/5 p-6 rounded-sm\">
          <div className=\"flex justify-between items-start mb-4\">
            <div>
              <p className=\"text-cyber-muted font-mono text-xs uppercase mb-1\">Vulnerabilities</p>
              <p className=\"text-3xl font-heading font-bold text-white\">{overview.totalVulnerabilities}</p>
            </div>
            <div className=\"p-3 bg-cyber-pink/10 rounded-sm\">
              <Shield className=\"w-6 h-6 text-cyber-pink\" />
            </div>
          </div>
          <div className=\"flex items-center gap-2 text-xs font-mono\">
            {vulnsTrend >= 0 ? (
              <>
                <TrendingUp className=\"w-4 h-4 text-cyber-pink\" />
                <span className=\"text-cyber-pink\">+{vulnsPercentChange}% this week</span>
              </>
            ) : (
              <>
                <TrendingDown className=\"w-4 h-4 text-cyber-green\" />
                <span className=\"text-cyber-green\">{vulnsPercentChange}% this week</span>
              </>
            )}
          </div>
        </div>

        <div className=\"bg-[#0b1120] border border-white/5 p-6 rounded-sm\">
          <div className=\"flex justify-between items-start mb-4\">
            <div>
              <p className=\"text-cyber-muted font-mono text-xs uppercase mb-1\">Critical Issues</p>
              <p className=\"text-3xl font-heading font-bold text-cyber-pink\">{overview.criticalVulns}</p>
            </div>
            <div className=\"p-3 bg-cyber-pink/10 rounded-sm\">
              <AlertTriangle className=\"w-6 h-6 text-cyber-pink\" />
            </div>
          </div>
          <div className=\"flex items-center gap-2 text-xs font-mono\">
            <span className=\"text-cyber-pink\">Requires immediate attention</span>
          </div>
        </div>
      </div>

      {/* Vulnerability Distribution */}
      <div className=\"grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6\">
        <div className=\"bg-[#0b1120] border border-white/5 p-6 rounded-sm\">
          <h3 className=\"text-lg font-heading font-bold text-white mb-4 flex items-center gap-2\">
            <PieChart className=\"w-5 h-5 text-cyber-green\" />
            Vulnerability Distribution
          </h3>

          <div className=\"space-y-4\">
            {[
              { label: 'Critical', count: overview.criticalVulns, color: 'bg-cyber-pink', textColor: 'text-cyber-pink' },
              { label: 'High', count: overview.highVulns, color: 'bg-orange-500', textColor: 'text-orange-500' },
              { label: 'Medium', count: overview.mediumVulns, color: 'bg-yellow-500', textColor: 'text-yellow-500' },
              { label: 'Low', count: overview.lowVulns, color: 'bg-cyber-green', textColor: 'text-cyber-green' },
            ].map((item) => {
              const percentage = overview.totalVulnerabilities > 0 
                ? ((item.count / overview.totalVulnerabilities) * 100).toFixed(1) 
                : '0';

              return (
                <div key={item.label}>
                  <div className=\"flex justify-between items-center mb-2\">
                    <span className=\"text-sm font-mono text-cyber-muted\">{item.label}</span>
                    <span className=\"text-sm font-mono text-white\">{item.count} ({percentage}%)</span>
                  </div>
                  <div className=\"w-full bg-white/5 rounded-full h-2\">
                    <div 
                      className={`${item.color} h-2 rounded-full transition-all duration-500`}
                      style={{ width: `${percentage}%` }}
                    ></div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Top Vulnerable Targets */}
        <div className=\"bg-[#0b1120] border border-white/5 p-6 rounded-sm\">
          <h3 className=\"text-lg font-heading font-bold text-white mb-4 flex items-center gap-2\">
            <BarChart3 className=\"w-5 h-5 text-cyber-green\" />
            Top Vulnerable Targets
          </h3>

          <div className=\"space-y-3\">
            {topTargets.slice(0, 5).map((target, idx) => (
              <div key={target.id} className=\"flex items-center justify-between p-3 bg-[#050812] border border-white/5 rounded-sm hover:border-cyber-green/30 transition-colors\">
                <div className=\"flex items-center gap-3\">
                  <span className=\"text-cyber-muted font-mono text-xs\">#{idx + 1}</span>
                  <div>
                    <p className=\"text-white font-mono text-sm font-bold\">{target.name}</p>
                    <p className=\"text-cyber-muted font-mono text-xs\">
                      Last scan: {new Date(target.lastScan).toLocaleDateString()}
                    </p>
                  </div>
                </div>
                <div className=\"text-right\">
                  <p className=\"text-white font-heading font-bold text-lg\">{target.vulnerabilityCount}</p>
                  <p className=\"text-cyber-pink font-mono text-xs\">{target.criticalCount} critical</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent Activity */}
      <div className=\"bg-[#0b1120] border border-white/5 p-6 rounded-sm\">
        <h3 className=\"text-lg font-heading font-bold text-white mb-4 flex items-center gap-2\">
          <Clock className=\"w-5 h-5 text-cyber-green\" />
          Recent Activity
        </h3>

        <div className=\"space-y-2\">
          {recentActivity.slice(0, 10).map((activity, idx) => (
            <div key={idx} className=\"flex items-center gap-3 p-3 bg-[#050812] border border-white/5 rounded-sm\">
              <div className={`p-2 rounded-sm ${
                activity.type === 'scan' ? 'bg-cyber-green/10' :
                activity.type === 'vulnerability' ? 'bg-cyber-pink/10' :
                'bg-cyber-blue/10'
              }`}>
                {activity.type === 'scan' ? <Activity className=\"w-4 h-4 text-cyber-green\" /> :
                 activity.type === 'vulnerability' ? <AlertTriangle className=\"w-4 h-4 text-cyber-pink\" /> :
                 <Shield className=\"w-4 h-4 text-cyber-blue\" />}
              </div>
              <div className=\"flex-1\">
                <p className=\"text-white font-mono text-sm\">{activity.message}</p>
                <p className=\"text-cyber-muted font-mono text-xs\">
                  {new Date(activity.timestamp).toLocaleString()}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { 
  Calendar, Clock, Play, Pause, Trash2, Plus, 
  Target, RefreshCcw, CheckCircle, XCircle, AlertCircle
} from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

interface ScheduledScan {
  id: string;
  targetId: string;
  targetName?: string;
  schedule: string;
  enabled: boolean;
  lastRun?: string;
  nextRun?: string;
  createdAt: string;
}

interface Target {
  id: string;
  name: string;
  scope: string;
}

export default function ScheduledScansPage() {
  const router = useRouter();
  const [scheduledScans, setScheduledScans] = useState<ScheduledScan[]>([]);
  const [targets, setTargets] = useState<Target[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);

  // Create form state
  const [selectedTargetId, setSelectedTargetId] = useState('');
  const [selectedSchedule, setSelectedSchedule] = useState('0 0 * * *'); // Daily at midnight
  const [customCron, setCustomCron] = useState('');
  const [useCustomCron, setUseCustomCron] = useState(false);

  const predefinedSchedules = [
    { label: 'Every Hour', value: '0 * * * *', description: 'Runs every hour' },
    { label: 'Every 6 Hours', value: '0 */6 * * *', description: 'Runs every 6 hours' },
    { label: 'Every 12 Hours', value: '0 */12 * * *', description: 'Runs every 12 hours' },
    { label: 'Daily at Midnight', value: '0 0 * * *', description: 'Runs daily at 00:00' },
    { label: 'Daily at 2 AM', value: '0 2 * * *', description: 'Runs daily at 02:00' },
    { label: 'Weekly (Sunday)', value: '0 0 * * 0', description: 'Runs every Sunday at midnight' },
    { label: 'Monthly (1st)', value: '0 0 1 * *', description: 'Runs on the 1st of each month' },
  ];

  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
      return;
    }
    fetchData();
  }, [router]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('vulnx_token');
      const baseUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000';

      const [scansRes, targetsRes] = await Promise.all([
        fetch(`${baseUrl}/scheduler/scheduled-scans`, {
          headers: { 'Authorization': `Bearer ${token}` },
        }),
        fetch(`${baseUrl}/targets`, {
          headers: { 'Authorization': `Bearer ${token}` },
        }),
      ]);

      if (!scansRes.ok || !targetsRes.ok) throw new Error('Failed to fetch data');

      const scansData = await scansRes.json();
      const targetsData = await targetsRes.json();

      // Enrich scheduled scans with target names
      const enrichedScans = scansData.map((scan: ScheduledScan) => ({
        ...scan,
        targetName: targetsData.find((t: Target) => t.id === scan.targetId)?.name || 'Unknown',
      }));

      setScheduledScans(enrichedScans);
      setTargets(targetsData);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateScheduledScan = async () => {
    if (!selectedTargetId) {
      alert('Please select a target');
      return;
    }

    const schedule = useCustomCron ? customCron : selectedSchedule;

    if (!schedule) {
      alert('Please select or enter a schedule');
      return;
    }

    try {
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/scheduler/scheduled-scans`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          targetId: selectedTargetId,
          schedule,
        }),
      });

      if (!response.ok) throw new Error('Failed to create scheduled scan');

      await fetchData();
      setShowCreateModal(false);
      setSelectedTargetId('');
      setCustomCron('');
      setUseCustomCron(false);
    } catch (err: any) {
      alert('Error: ' + err.message);
    }
  };

  const handleToggleSchedule = async (id: string, currentStatus: boolean) => {
    try {
      const token = localStorage.getItem('vulnx_token');
      const action = currentStatus ? 'pause' : 'resume';

      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/scheduler/scheduled-scans/${id}/${action}`, {
        method: 'PATCH',
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (!response.ok) throw new Error(`Failed to ${action} scheduled scan`);

      await fetchData();
    } catch (err: any) {
      alert('Error: ' + err.message);
    }
  };

  const handleDeleteSchedule = async (id: string) => {
    if (!confirm('Are you sure you want to delete this scheduled scan?')) return;

    try {
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/scheduler/scheduled-scans/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (!response.ok) throw new Error('Failed to delete scheduled scan');

      await fetchData();
    } catch (err: any) {
      alert('Error: ' + err.message);
    }
  };

  const parseCronDescription = (cron: string): string => {
    const predefined = predefinedSchedules.find(s => s.value === cron);
    if (predefined) return predefined.description;
    return cron;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812]">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-cyber-green border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-cyber-green font-mono text-sm">Loading Scheduled Scans...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050812] text-white p-6">
      {/* Header */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-3xl font-heading font-bold text-white mb-2">
              Scheduled Scans
            </h1>
            <p className="text-cyber-muted font-mono text-sm">
              Automate your security scans with cron-based scheduling
            </p>
          </div>

          <div className="flex gap-3">
            <button
              onClick={fetchData}
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors flex items-center gap-2"
            >
              <RefreshCcw className="w-4 h-4" />
              Refresh
            </button>

            <button
              onClick={() => setShowCreateModal(true)}
              className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors flex items-center gap-2"
            >
              <Plus className="w-4 h-4" />
              New Schedule
            </button>

            <Link
              href="/dashboard"
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors"
            >
              Back to Dashboard
            </Link>
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Total Schedules</p>
          <p className="text-2xl font-heading font-bold text-white">{scheduledScans.length}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Active</p>
          <p className="text-2xl font-heading font-bold text-cyber-green">
            {scheduledScans.filter(s => s.enabled).length}
          </p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Paused</p>
          <p className="text-2xl font-heading font-bold text-cyber-pink">
            {scheduledScans.filter(s => !s.enabled).length}
          </p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Available Targets</p>
          <p className="text-2xl font-heading font-bold text-cyber-blue">{targets.length}</p>
        </div>
      </div>

      {/* Scheduled Scans List */}
      <div className="bg-[#0b1120] border border-white/5 rounded-sm overflow-hidden">
        <div className="p-4 border-b border-white/5">
          <h2 className="text-lg font-heading font-bold text-white">Active Schedules</h2>
        </div>

        {scheduledScans.length === 0 ? (
          <div className="p-12 text-center">
            <Calendar className="w-16 h-16 text-cyber-muted mx-auto mb-4" />
            <p className="text-cyber-muted font-mono text-sm mb-4">No scheduled scans yet</p>
            <button
              onClick={() => setShowCreateModal(true)}
              className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm"
            >
              Create Your First Schedule
            </button>
          </div>
        ) : (
          <div className="divide-y divide-white/5">
            {scheduledScans.map((scan) => (
              <div key={scan.id} className="p-4 hover:bg-white/[0.02] transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4 flex-1">
                    <div className={`p-3 rounded-sm ${scan.enabled ? 'bg-cyber-green/10' : 'bg-cyber-muted/10'}`}>
                      {scan.enabled ? (
                        <CheckCircle className="w-5 h-5 text-cyber-green" />
                      ) : (
                        <XCircle className="w-5 h-5 text-cyber-muted" />
                      )}
                    </div>

                    <div className="flex-1">
                      <div className="flex items-center gap-3 mb-1">
                        <h3 className="text-white font-heading font-bold text-base">
                          {scan.targetName}
                        </h3>
                        <span className={`px-2 py-0.5 rounded-sm text-xs font-mono font-bold ${
                          scan.enabled 
                            ? 'bg-cyber-green/10 text-cyber-green' 
                            : 'bg-cyber-muted/10 text-cyber-muted'
                        }`}>
                          {scan.enabled ? 'ACTIVE' : 'PAUSED'}
                        </span>
                      </div>

                      <div className="flex items-center gap-4 text-xs font-mono text-cyber-muted">
                        <span className="flex items-center gap-1">
                          <Clock className="w-3 h-3" />
                          {parseCronDescription(scan.schedule)}
                        </span>
                        {scan.nextRun && (
                          <span className="flex items-center gap-1">
                            <Calendar className="w-3 h-3" />
                            Next: {new Date(scan.nextRun).toLocaleString()}
                          </span>
                        )}
                        {scan.lastRun && (
                          <span className="flex items-center gap-1">
                            Last: {new Date(scan.lastRun).toLocaleString()}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => handleToggleSchedule(scan.id, scan.enabled)}
                      className={`p-2 rounded-sm border transition-colors ${
                        scan.enabled
                          ? 'border-cyber-pink/20 text-cyber-pink hover:bg-cyber-pink/10'
                          : 'border-cyber-green/20 text-cyber-green hover:bg-cyber-green/10'
                      }`}
                      title={scan.enabled ? 'Pause' : 'Resume'}
                    >
                      {scan.enabled ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
                    </button>

                    <button
                      onClick={() => handleDeleteSchedule(scan.id)}
                      className="p-2 rounded-sm border border-cyber-pink/20 text-cyber-pink hover:bg-cyber-pink/10 transition-colors"
                      title="Delete"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Create Modal */}
      {showCreateModal && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-6">
          <div className="bg-[#0b1120] border border-white/10 rounded-sm max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-white/5">
              <h2 className="text-xl font-heading font-bold text-white">Create Scheduled Scan</h2>
            </div>

            <div className="p-6 space-y-6">
              {/* Target Selection */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-2">
                  Select Target *
                </label>
                <select
                  value={selectedTargetId}
                  onChange={(e) => setSelectedTargetId(e.target.value)}
                  className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm px-4 py-3 rounded-sm focus:border-cyber-green outline-none"
                >
                  <option value="">-- Select a target --</option>
                  {targets.map((target) => (
                    <option key={target.id} value={target.id}>
                      {target.name} ({target.scope})
                    </option>
                  ))}
                </select>
              </div>

              {/* Schedule Type */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-2">
                  Schedule Type
                </label>
                <div className="flex gap-4 mb-4">
                  <button
                    onClick={() => setUseCustomCron(false)}
                    className={`flex-1 px-4 py-2 rounded-sm font-mono text-xs transition-colors ${
                      !useCustomCron
                        ? 'bg-cyber-green text-black'
                        : 'bg-[#050812] border border-white/10 text-cyber-muted'
                    }`}
                  >
                    Predefined
                  </button>
                  <button
                    onClick={() => setUseCustomCron(true)}
                    className={`flex-1 px-4 py-2 rounded-sm font-mono text-xs transition-colors ${
                      useCustomCron
                        ? 'bg-cyber-green text-black'
                        : 'bg-[#050812] border border-white/10 text-cyber-muted'
                    }`}
                  >
                    Custom Cron
                  </button>
                </div>

                {!useCustomCron ? (
                  <select
                    value={selectedSchedule}
                    onChange={(e) => setSelectedSchedule(e.target.value)}
                    className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm px-4 py-3 rounded-sm focus:border-cyber-green outline-none"
                  >
                    {predefinedSchedules.map((schedule) => (
                      <option key={schedule.value} value={schedule.value}>
                        {schedule.label} - {schedule.description}
                      </option>
                    ))}
                  </select>
                ) : (
                  <div>
                    <input
                      type="text"
                      value={customCron}
                      onChange={(e) => setCustomCron(e.target.value)}
                      placeholder="0 0 * * * (cron expression)"
                      className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm px-4 py-3 rounded-sm focus:border-cyber-green outline-none"
                    />
                    <p className="text-xs font-mono text-cyber-muted mt-2">
                      Format: minute hour day month weekday (e.g., "0 2 * * *" = daily at 2 AM)
                    </p>
                  </div>
                )}
              </div>

              {/* Info Box */}
              <div className="bg-cyber-blue/10 border border-cyber-blue/20 p-4 rounded-sm">
                <div className="flex gap-3">
                  <AlertCircle className="w-5 h-5 text-cyber-blue shrink-0 mt-0.5" />
                  <div className="text-xs font-mono text-cyber-blue">
                    <p className="font-bold mb-1">Scheduled Scan Info:</p>
                    <ul className="list-disc list-inside space-y-1">
                      <li>Scans will run automatically based on the schedule</li>
                      <li>You can pause/resume schedules at any time</li>
                      <li>Real-time logs will be available during execution</li>
                      <li>Email notifications will be sent on completion</li>
                    </ul>
                  </div>
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-white/5 flex justify-end gap-3">
              <button
                onClick={() => {
                  setShowCreateModal(false);
                  setSelectedTargetId('');
                  setCustomCron('');
                  setUseCustomCron(false);
                }}
                className="px-4 py-2 bg-[#050812] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateScheduledScan}
                className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors"
              >
                Create Schedule
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { 
  Shield, Bell, AlertTriangle, Plus, Trash2, 
  RefreshCcw, Eye, EyeOff, Mail, MessageSquare,
  Activity, TrendingUp, Lock, Wifi
} from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

interface MonitoringRule {
  id: string;
  targetId: string;
  targetName?: string;
  type: 'NEW_VULNERABILITY' | 'SEVERITY_CHANGE' | 'PORT_CHANGE' | 'SSL_EXPIRY';
  enabled: boolean;
  threshold?: any;
  notifyEmail: boolean;
  notifySlack: boolean;
  createdAt: string;
}

interface Target {
  id: string;
  name: string;
  scope: string;
}

interface MonitoringLog {
  id: string;
  targetId: string;
  changeType: string;
  oldValue?: string;
  newValue?: string;
  severity?: string;
  notified: boolean;
  createdAt: string;
}

export default function MonitoringPage() {
  const router = useRouter();
  const [rules, setRules] = useState<MonitoringRule[]>([]);
  const [logs, setLogs] = useState<MonitoringLog[]>([]);
  const [targets, setTargets] = useState<Target[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [activeTab, setActiveTab] = useState<'rules' | 'logs'>('rules');

  // Create form state
  const [selectedTargetId, setSelectedTargetId] = useState('');
  const [selectedType, setSelectedType] = useState<MonitoringRule['type']>('NEW_VULNERABILITY');
  const [notifyEmail, setNotifyEmail] = useState(true);
  const [notifySlack, setNotifySlack] = useState(false);

  const ruleTypes = [
    { 
      value: 'NEW_VULNERABILITY', 
      label: 'New Vulnerability', 
      description: 'Alert when new vulnerabilities are discovered',
      icon: AlertTriangle,
      color: 'text-cyber-pink'
    },
    { 
      value: 'SEVERITY_CHANGE', 
      label: 'Severity Change', 
      description: 'Alert when vulnerability severity changes',
      icon: TrendingUp,
      color: 'text-orange-500'
    },
    { 
      value: 'PORT_CHANGE', 
      label: 'Port Change', 
      description: 'Alert when open ports change',
      icon: Wifi,
      color: 'text-cyber-blue'
    },
    { 
      value: 'SSL_EXPIRY', 
      label: 'SSL Expiry', 
      description: 'Alert when SSL certificates are expiring',
      icon: Lock,
      color: 'text-yellow-500'
    },
  ];

  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
      return;
    }
    fetchData();
  }, [router]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('vulnx_token');
      const baseUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000';

      const [rulesRes, logsRes, targetsRes] = await Promise.all([
        fetch(`${baseUrl}/monitoring/rules`, {
          headers: { 'Authorization': `Bearer ${token}` },
        }),
        fetch(`${baseUrl}/monitoring/logs?limit=50`, {
          headers: { 'Authorization': `Bearer ${token}` },
        }),
        fetch(`${baseUrl}/targets`, {
          headers: { 'Authorization': `Bearer ${token}` },
        }),
      ]);

      if (!rulesRes.ok || !targetsRes.ok) throw new Error('Failed to fetch data');

      const rulesData = await rulesRes.json();
      const logsData = logsRes.ok ? await logsRes.json() : [];
      const targetsData = await targetsRes.json();

      // Enrich rules with target names
      const enrichedRules = rulesData.map((rule: MonitoringRule) => ({
        ...rule,
        targetName: targetsData.find((t: Target) => t.id === rule.targetId)?.name || 'Unknown',
      }));

      setRules(enrichedRules);
      setLogs(logsData);
      setTargets(targetsData);
    } catch (err: any) {
      console.error('Error fetching data:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateRule = async () => {
    if (!selectedTargetId) {
      alert('Please select a target');
      return;
    }

    try {
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/monitoring/rules`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          targetId: selectedTargetId,
          type: selectedType,
          enabled: true,
          notifyEmail,
          notifySlack,
        }),
      });

      if (!response.ok) throw new Error('Failed to create monitoring rule');

      await fetchData();
      setShowCreateModal(false);
      setSelectedTargetId('');
      setSelectedType('NEW_VULNERABILITY');
      setNotifyEmail(true);
      setNotifySlack(false);
    } catch (err: any) {
      alert('Error: ' + err.message);
    }
  };

  const handleDeleteRule = async (id: string) => {
    if (!confirm('Are you sure you want to delete this monitoring rule?')) return;

    try {
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/monitoring/rules/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (!response.ok) throw new Error('Failed to delete monitoring rule');

      await fetchData();
    } catch (err: any) {
      alert('Error: ' + err.message);
    }
  };

  const handleTriggerCheck = async () => {
    try {
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/monitoring/trigger`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (!response.ok) throw new Error('Failed to trigger monitoring check');

      alert('Monitoring check triggered successfully!');
      setTimeout(fetchData, 2000);
    } catch (err: any) {
      alert('Error: ' + err.message);
    }
  };

  const getRuleTypeInfo = (type: string) => {
    return ruleTypes.find(t => t.value === type) || ruleTypes[0];
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812]">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-cyber-green border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-cyber-green font-mono text-sm">Loading Monitoring...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050812] text-white p-6">
      {/* Header */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-3xl font-heading font-bold text-white mb-2">
              Continuous Monitoring
            </h1>
            <p className="text-cyber-muted font-mono text-sm">
              Real-time security change detection and alerting
            </p>
          </div>

          <div className="flex gap-3">
            <button
              onClick={handleTriggerCheck}
              className="px-4 py-2 bg-cyber-blue/10 border border-cyber-blue/20 text-cyber-blue hover:bg-cyber-blue/20 font-mono text-xs rounded-sm transition-colors flex items-center gap-2"
            >
              <Activity className="w-4 h-4" />
              Trigger Check
            </button>

            <button
              onClick={fetchData}
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors flex items-center gap-2"
            >
              <RefreshCcw className="w-4 h-4" />
              Refresh
            </button>

            <button
              onClick={() => setShowCreateModal(true)}
              className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors flex items-center gap-2"
            >
              <Plus className="w-4 h-4" />
              New Rule
            </button>

            <Link
              href="/dashboard"
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors"
            >
              Back
            </Link>
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Total Rules</p>
          <p className="text-2xl font-heading font-bold text-white">{rules.length}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Active Rules</p>
          <p className="text-2xl font-heading font-bold text-cyber-green">
            {rules.filter(r => r.enabled).length}
          </p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Changes Detected</p>
          <p className="text-2xl font-heading font-bold text-cyber-blue">{logs.length}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Monitored Targets</p>
          <p className="text-2xl font-heading font-bold text-cyber-purple">
            {new Set(rules.map(r => r.targetId)).size}
          </p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-2 mb-6">
        <button
          onClick={() => setActiveTab('rules')}
          className={`px-4 py-2 font-mono text-xs rounded-sm transition-colors ${
            activeTab === 'rules'
              ? 'bg-cyber-green text-black'
              : 'bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white'
          }`}
        >
          Monitoring Rules ({rules.length})
        </button>
        <button
          onClick={() => setActiveTab('logs')}
          className={`px-4 py-2 font-mono text-xs rounded-sm transition-colors ${
            activeTab === 'logs'
              ? 'bg-cyber-green text-black'
              : 'bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white'
          }`}
        >
          Change Logs ({logs.length})
        </button>
      </div>

      {/* Content */}
      {activeTab === 'rules' ? (
        <div className="bg-[#0b1120] border border-white/5 rounded-sm overflow-hidden">
          <div className="p-4 border-b border-white/5">
            <h2 className="text-lg font-heading font-bold text-white">Monitoring Rules</h2>
          </div>

          {rules.length === 0 ? (
            <div className="p-12 text-center">
              <Shield className="w-16 h-16 text-cyber-muted mx-auto mb-4" />
              <p className="text-cyber-muted font-mono text-sm mb-4">No monitoring rules configured</p>
              <button
                onClick={() => setShowCreateModal(true)}
                className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm"
              >
                Create Your First Rule
              </button>
            </div>
          ) : (
            <div className="divide-y divide-white/5">
              {rules.map((rule) => {
                const typeInfo = getRuleTypeInfo(rule.type);
                const Icon = typeInfo.icon;

                return (
                  <div key={rule.id} className="p-4 hover:bg-white/[0.02] transition-colors">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-4 flex-1">
                        <div className={`p-3 rounded-sm ${rule.enabled ? 'bg-cyber-green/10' : 'bg-cyber-muted/10'}`}>
                          <Icon className={`w-5 h-5 ${rule.enabled ? typeInfo.color : 'text-cyber-muted'}`} />
                        </div>

                        <div className="flex-1">
                          <div className="flex items-center gap-3 mb-1">
                            <h3 className="text-white font-heading font-bold text-base">
                              {rule.targetName}
                            </h3>
                            <span className={`px-2 py-0.5 rounded-sm text-xs font-mono font-bold ${
                              rule.enabled 
                                ? 'bg-cyber-green/10 text-cyber-green' 
                                : 'bg-cyber-muted/10 text-cyber-muted'
                            }`}>
                              {rule.enabled ? 'ACTIVE' : 'DISABLED'}
                            </span>
                          </div>

                          <div className="flex items-center gap-4 text-xs font-mono text-cyber-muted">
                            <span className={typeInfo.color}>{typeInfo.label}</span>
                            <span className="flex items-center gap-1">
                              {rule.notifyEmail && (
                                <span className="flex items-center gap-1 bg-cyber-blue/10 px-2 py-0.5 rounded-sm">
                                  <Mail className="w-3 h-3" /> Email
                                </span>
                              )}
                              {rule.notifySlack && (
                                <span className="flex items-center gap-1 bg-cyber-purple/10 px-2 py-0.5 rounded-sm">
                                  <MessageSquare className="w-3 h-3" /> Slack
                                </span>
                              )}
                            </span>
                          </div>
                        </div>
                      </div>

                      <div className="flex items-center gap-2">
                        <button
                          onClick={() => handleDeleteRule(rule.id)}
                          className="p-2 rounded-sm border border-cyber-pink/20 text-cyber-pink hover:bg-cyber-pink/10 transition-colors"
                          title="Delete"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      ) : (
        <div className="bg-[#0b1120] border border-white/5 rounded-sm overflow-hidden">
          <div className="p-4 border-b border-white/5">
            <h2 className="text-lg font-heading font-bold text-white">Change Detection Logs</h2>
          </div>

          {logs.length === 0 ? (
            <div className="p-12 text-center">
              <Activity className="w-16 h-16 text-cyber-muted mx-auto mb-4" />
              <p className="text-cyber-muted font-mono text-sm">No changes detected yet</p>
            </div>
          ) : (
            <div className="divide-y divide-white/5">
              {logs.map((log) => (
                <div key={log.id} className="p-4 hover:bg-white/[0.02] transition-colors">
                  <div className="flex items-center gap-4">
                    <div className={`p-2 rounded-sm ${
                      log.severity === 'CRITICAL' ? 'bg-cyber-pink/10' :
                      log.severity === 'HIGH' ? 'bg-orange-500/10' :
                      'bg-cyber-blue/10'
                    }`}>
                      <AlertTriangle className={`w-4 h-4 ${
                        log.severity === 'CRITICAL' ? 'text-cyber-pink' :
                        log.severity === 'HIGH' ? 'text-orange-500' :
                        'text-cyber-blue'
                      }`} />
                    </div>

                    <div className="flex-1">
                      <p className="text-white font-mono text-sm mb-1">{log.changeType}</p>
                      <p className="text-cyber-muted font-mono text-xs">
                        {new Date(log.createdAt).toLocaleString()}
                        {log.notified && <span className="ml-2 text-cyber-green">• Notified</span>}
                      </p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Create Modal */}
      {showCreateModal && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-6">
          <div className="bg-[#0b1120] border border-white/10 rounded-sm max-w-2xl w-full">
            <div className="p-6 border-b border-white/5">
              <h2 className="text-xl font-heading font-bold text-white">Create Monitoring Rule</h2>
            </div>

            <div className="p-6 space-y-6">
              {/* Target Selection */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-2">
                  Select Target *
                </label>
                <select
                  value={selectedTargetId}
                  onChange={(e) => setSelectedTargetId(e.target.value)}
                  className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm px-4 py-3 rounded-sm focus:border-cyber-green outline-none"
                >
                  <option value="">-- Select a target --</option>
                  {targets.map((target) => (
                    <option key={target.id} value={target.id}>
                      {target.name} ({target.scope})
                    </option>
                  ))}
                </select>
              </div>

              {/* Rule Type */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-3">
                  Monitoring Type *
                </label>
                <div className="grid grid-cols-2 gap-3">
                  {ruleTypes.map((type) => {
                    const Icon = type.icon;
                    return (
                      <button
                        key={type.value}
                        onClick={() => setSelectedType(type.value as any)}
                        className={`p-4 rounded-sm border transition-all text-left ${
                          selectedType === type.value
                            ? 'border-cyber-green bg-cyber-green/10'
                            : 'border-white/10 bg-[#050812] hover:border-white/20'
                        }`}
                      >
                        <Icon className={`w-5 h-5 ${type.color} mb-2`} />
                        <p className="text-white font-mono text-sm font-bold mb-1">{type.label}</p>
                        <p className="text-cyber-muted font-mono text-xs">{type.description}</p>
                      </button>
                    );
                  })}
                </div>
              </div>

              {/* Notification Channels */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-3">
                  Notification Channels
                </label>
                <div className="space-y-2">
                  <label className="flex items-center gap-3 p-3 bg-[#050812] border border-white/10 rounded-sm cursor-pointer hover:border-cyber-green/30 transition-colors">
                    <input
                      type="checkbox"
                      checked={notifyEmail}
                      onChange={(e) => setNotifyEmail(e.target.checked)}
                      className="w-4 h-4"
                    />
                    <Mail className="w-4 h-4 text-cyber-blue" />
                    <span className="text-white font-mono text-sm">Email Notifications</span>
                  </label>

                  <label className="flex items-center gap-3 p-3 bg-[#050812] border border-white/10 rounded-sm cursor-pointer hover:border-cyber-green/30 transition-colors">
                    <input
                      type="checkbox"
                      checked={notifySlack}
                      onChange={(e) => setNotifySlack(e.target.checked)}
                      className="w-4 h-4"
                    />
                    <MessageSquare className="w-4 h-4 text-cyber-purple" />
                    <span className="text-white font-mono text-sm">Slack Notifications</span>
                  </label>
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-white/5 flex justify-end gap-3">
              <button
                onClick={() => {
                  setShowCreateModal(false);
                  setSelectedTargetId('');
                  setSelectedType('NEW_VULNERABILITY');
                  setNotifyEmail(true);
                  setNotifySlack(false);
                }}
                className="px-4 py-2 bg-[#050812] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateRule}
                className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors"
              >
                Create Rule
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { 
  Shield, AlertTriangle, Search, Filter, ExternalLink,
  Calendar, TrendingUp, Database, Github, Bug, RefreshCcw,
  ChevronDown, ChevronUp, Eye, Download
} from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

interface ThreatIntel {
  id: string;
  type: 'CVE' | 'EXPLOIT' | 'ADVISORY';
  externalId: string;
  title: string;
  description: string;
  severity?: string;
  cvssScore?: number;
  published: string;
  modified?: string;
  references: string[];
  tags: string[];
}

export default function ThreatIntelPage() {
  const router = useRouter();
  const [threats, setThreats] = useState<ThreatIntel[]>([]);
  const [filteredThreats, setFilteredThreats] = useState<ThreatIntel[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedType, setSelectedType] = useState<'ALL' | 'CVE' | 'EXPLOIT' | 'ADVISORY'>('ALL');
  const [selectedSeverity, setSelectedSeverity] = useState<'ALL' | 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW'>('ALL');
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [sortBy, setSortBy] = useState<'date' | 'severity'>('date');

  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
      return;
    }
    fetchThreats();
  }, [router]);

  useEffect(() => {
    filterThreats();
  }, [threats, searchQuery, selectedType, selectedSeverity, sortBy]);

  const fetchThreats = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/threat-intel`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (!response.ok) throw new Error('Failed to fetch threat intelligence');

      const data = await response.json();
      setThreats(data);
    } catch (err: any) {
      console.error('Error fetching threats:', err);
    } finally {
      setLoading(false);
    }
  };

  const filterThreats = () => {
    let filtered = [...threats];

    // Filter by search query
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.filter(t => 
        t.title.toLowerCase().includes(query) ||
        t.description.toLowerCase().includes(query) ||
        t.externalId.toLowerCase().includes(query) ||
        t.tags.some(tag => tag.toLowerCase().includes(query))
      );
    }

    // Filter by type
    if (selectedType !== 'ALL') {
      filtered = filtered.filter(t => t.type === selectedType);
    }

    // Filter by severity
    if (selectedSeverity !== 'ALL') {
      filtered = filtered.filter(t => t.severity === selectedSeverity);
    }

    // Sort
    if (sortBy === 'date') {
      filtered.sort((a, b) => new Date(b.published).getTime() - new Date(a.published).getTime());
    } else if (sortBy === 'severity') {
      const severityOrder = { 'CRITICAL': 0, 'HIGH': 1, 'MEDIUM': 2, 'LOW': 3 };
      filtered.sort((a, b) => {
        const aOrder = severityOrder[a.severity as keyof typeof severityOrder] ?? 999;
        const bOrder = severityOrder[b.severity as keyof typeof severityOrder] ?? 999;
        return aOrder - bOrder;
      });
    }

    setFilteredThreats(filtered);
  };

  const getSeverityColor = (severity?: string) => {
    switch (severity) {
      case 'CRITICAL': return 'text-cyber-pink bg-cyber-pink/10 border-cyber-pink/20';
      case 'HIGH': return 'text-orange-500 bg-orange-500/10 border-orange-500/20';
      case 'MEDIUM': return 'text-yellow-500 bg-yellow-500/10 border-yellow-500/20';
      case 'LOW': return 'text-cyber-green bg-cyber-green/10 border-cyber-green/20';
      default: return 'text-cyber-muted bg-cyber-muted/10 border-cyber-muted/20';
    }
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'CVE': return <Shield className="w-4 h-4" />;
      case 'EXPLOIT': return <Bug className="w-4 h-4" />;
      case 'ADVISORY': return <Github className="w-4 h-4" />;
      default: return <AlertTriangle className="w-4 h-4" />;
    }
  };

  const getTypeColor = (type: string) => {
    switch (type) {
      case 'CVE': return 'text-cyber-pink bg-cyber-pink/10';
      case 'EXPLOIT': return 'text-orange-500 bg-orange-500/10';
      case 'ADVISORY': return 'text-cyber-blue bg-cyber-blue/10';
      default: return 'text-cyber-muted bg-cyber-muted/10';
    }
  };

  const stats = {
    total: threats.length,
    cve: threats.filter(t => t.type === 'CVE').length,
    exploits: threats.filter(t => t.type === 'EXPLOIT').length,
    advisories: threats.filter(t => t.type === 'ADVISORY').length,
    critical: threats.filter(t => t.severity === 'CRITICAL').length,
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812]">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-cyber-green border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-cyber-green font-mono text-sm">Loading Threat Intelligence...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050812] text-white p-6">
      {/* Header */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-3xl font-heading font-bold text-white mb-2">
              Threat Intelligence
            </h1>
            <p className="text-cyber-muted font-mono text-sm">
              Real-time CVE, exploits, and security advisories from NVD, Exploit-DB, and GitHub
            </p>
          </div>

          <div className="flex gap-3">
            <button
              onClick={fetchThreats}
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors flex items-center gap-2"
            >
              <RefreshCcw className="w-4 h-4" />
              Refresh
            </button>

            <Link
              href="/dashboard"
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors"
            >
              Back to Dashboard
            </Link>
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-5 gap-4 mb-6">
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Total Threats</p>
          <p className="text-2xl font-heading font-bold text-white">{stats.total}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">CVEs</p>
          <p className="text-2xl font-heading font-bold text-cyber-pink">{stats.cve}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Exploits</p>
          <p className="text-2xl font-heading font-bold text-orange-500">{stats.exploits}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Advisories</p>
          <p className="text-2xl font-heading font-bold text-cyber-blue">{stats.advisories}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Critical</p>
          <p className="text-2xl font-heading font-bold text-cyber-pink">{stats.critical}</p>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm mb-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {/* Search */}
          <div className="md:col-span-2">
            <div className="relative">
              <Search className="absolute left-3 top-3 w-4 h-4 text-cyber-muted" />
              <input
                type="text"
                placeholder="Search threats, CVEs, tags..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm pl-10 pr-4 py-2 rounded-sm focus:border-cyber-green outline-none"
              />
            </div>
          </div>

          {/* Type Filter */}
          <div>
            <select
              value={selectedType}
              onChange={(e) => setSelectedType(e.target.value as any)}
              className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm px-4 py-2 rounded-sm focus:border-cyber-green outline-none"
            >
              <option value="ALL">All Types</option>
              <option value="CVE">CVE Only</option>
              <option value="EXPLOIT">Exploits Only</option>
              <option value="ADVISORY">Advisories Only</option>
            </select>
          </div>

          {/* Severity Filter */}
          <div>
            <select
              value={selectedSeverity}
              onChange={(e) => setSelectedSeverity(e.target.value as any)}
              className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm px-4 py-2 rounded-sm focus:border-cyber-green outline-none"
            >
              <option value="ALL">All Severities</option>
              <option value="CRITICAL">Critical</option>
              <option value="HIGH">High</option>
              <option value="MEDIUM">Medium</option>
              <option value="LOW">Low</option>
            </select>
          </div>
        </div>

        <div className="flex items-center justify-between mt-4 pt-4 border-t border-white/5">
          <p className="text-cyber-muted font-mono text-xs">
            Showing {filteredThreats.length} of {threats.length} threats
          </p>

          <div className="flex items-center gap-2">
            <span className="text-cyber-muted font-mono text-xs">Sort by:</span>
            <button
              onClick={() => setSortBy('date')}
              className={`px-3 py-1 rounded-sm font-mono text-xs transition-colors ${
                sortBy === 'date'
                  ? 'bg-cyber-green text-black'
                  : 'bg-[#050812] border border-white/10 text-cyber-muted hover:text-white'
              }`}
            >
              Date
            </button>
            <button
              onClick={() => setSortBy('severity')}
              className={`px-3 py-1 rounded-sm font-mono text-xs transition-colors ${
                sortBy === 'severity'
                  ? 'bg-cyber-green text-black'
                  : 'bg-[#050812] border border-white/10 text-cyber-muted hover:text-white'
              }`}
            >
              Severity
            </button>
          </div>
        </div>
      </div>

      {/* Threats List */}
      <div className="space-y-3">
        {filteredThreats.length === 0 ? (
          <div className="bg-[#0b1120] border border-white/5 p-12 rounded-sm text-center">
            <Database className="w-16 h-16 text-cyber-muted mx-auto mb-4" />
            <p className="text-cyber-muted font-mono text-sm">No threats found matching your filters</p>
          </div>
        ) : (
          filteredThreats.map((threat) => (
            <div key={threat.id} className="bg-[#0b1120] border border-white/5 rounded-sm overflow-hidden hover:border-white/10 transition-colors">
              <div className="p-4">
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-start gap-3 flex-1">
                    <div className={`p-2 rounded-sm ${getTypeColor(threat.type)}`}>
                      {getTypeIcon(threat.type)}
                    </div>

                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-2">
                        <h3 className="text-white font-heading font-bold text-base">
                          {threat.externalId}
                        </h3>
                        <span className={`px-2 py-0.5 rounded-sm text-xs font-mono font-bold border ${getSeverityColor(threat.severity)}`}>
                          {threat.severity || 'N/A'}
                        </span>
                        {threat.cvssScore && (
                          <span className="px-2 py-0.5 rounded-sm text-xs font-mono font-bold bg-cyber-blue/10 text-cyber-blue">
                            CVSS {threat.cvssScore.toFixed(1)}
                          </span>
                        )}
                      </div>

                      <p className="text-white font-mono text-sm mb-2">{threat.title}</p>

                      <div className="flex items-center gap-4 text-xs font-mono text-cyber-muted">
                        <span className="flex items-center gap-1">
                          <Calendar className="w-3 h-3" />
                          {new Date(threat.published).toLocaleDateString()}
                        </span>
                        {threat.tags.length > 0 && (
                          <div className="flex items-center gap-1">
                            {threat.tags.slice(0, 3).map((tag, idx) => (
                              <span key={idx} className="px-2 py-0.5 bg-cyber-muted/10 rounded-sm">
                                {tag}
                              </span>
                            ))}
                            {threat.tags.length > 3 && (
                              <span className="px-2 py-0.5 bg-cyber-muted/10 rounded-sm">
                                +{threat.tags.length - 3}
                              </span>
                            )}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>

                  <button
                    onClick={() => setExpandedId(expandedId === threat.id ? null : threat.id)}
                    className="p-2 rounded-sm border border-white/10 text-cyber-muted hover:text-white hover:border-cyber-green/30 transition-colors"
                  >
                    {expandedId === threat.id ? (
                      <ChevronUp className="w-4 h-4" />
                    ) : (
                      <ChevronDown className="w-4 h-4" />
                    )}
                  </button>
                </div>

                {expandedId === threat.id && (
                  <div className="mt-4 pt-4 border-t border-white/5">
                    <div className="space-y-4">
                      <div>
                        <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Description</p>
                        <p className="text-white font-mono text-sm leading-relaxed">
                          {threat.description}
                        </p>
                      </div>

                      {threat.references.length > 0 && (
                        <div>
                          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">References</p>
                          <div className="space-y-1">
                            {threat.references.slice(0, 5).map((ref, idx) => (
                              <a
                                key={idx}
                                href={ref}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="flex items-center gap-2 text-cyber-blue hover:text-cyber-green font-mono text-xs transition-colors"
                              >
                                <ExternalLink className="w-3 h-3" />
                                {ref.length > 60 ? ref.substring(0, 60) + '...' : ref}
                              </a>
                            ))}
                          </div>
                        </div>
                      )}

                      {threat.modified && (
                        <div>
                          <p className="text-cyber-muted font-mono text-xs">
                            Last modified: {new Date(threat.modified).toLocaleString()}
                          </p>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { 
  FileText, Download, Plus, Trash2, RefreshCcw,
  Calendar, File, FileJson, FileCode, Eye, Clock
} from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';

interface Report {
  id: string;
  title: string;
  format: 'PDF' | 'MARKDOWN' | 'JSON';
  downloadUrl: string;
  createdAt: string;
}

interface Target {
  id: string;
  name: string;
  scope: string;
}

export default function ReportsPage() {
  const router = useRouter();
  const [reports, setReports] = useState<Report[]>([]);
  const [targets, setTargets] = useState<Target[]>([]);
  const [loading, setLoading] = useState(true);
