  const [showCreateModal, setShowCreateModal] = useState(false);

  // Create form state
  const [reportTitle, setReportTitle] = useState('');
  const [selectedFormat, setSelectedFormat] = useState<'PDF' | 'MARKDOWN' | 'JSON'>('PDF');
  const [selectedTargets, setSelectedTargets] = useState<string[]>([]);
  const [includeVulns, setIncludeVulns] = useState(true);
  const [includeScans, setIncludeScans] = useState(true);
  const [includeRecommendations, setIncludeRecommendations] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('vulnx_token');
    if (!token) {
      router.push('/login');
      return;
    }
    fetchData();
  }, [router]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('vulnx_token');
      const baseUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000';

      const [reportsRes, targetsRes] = await Promise.all([
        fetch(`${baseUrl}/reports`, {
          headers: { 'Authorization': `Bearer ${token}` },
        }),
        fetch(`${baseUrl}/targets`, {
          headers: { 'Authorization': `Bearer ${token}` },
        }),
      ]);

      if (!reportsRes.ok || !targetsRes.ok) throw new Error('Failed to fetch data');

      const reportsData = await reportsRes.json();
      const targetsData = await targetsRes.json();

      setReports(reportsData);
      setTargets(targetsData);
    } catch (err: any) {
      console.error('Error fetching data:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleGenerateReport = async () => {
    if (!reportTitle.trim()) {
      alert('Please enter a report title');
      return;
    }

    if (selectedTargets.length === 0) {
      alert('Please select at least one target');
      return;
    }

    try {
      setGenerating(true);
      const token = localStorage.getItem('vulnx_token');

      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/reports`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          title: reportTitle,
          format: selectedFormat,
          targetIds: selectedTargets,
          includeVulnerabilities: includeVulns,
          includeScans: includeScans,
          includeRecommendations: includeRecommendations,
        }),
      });

      if (!response.ok) throw new Error('Failed to generate report');

      const newReport = await response.json();

      // Download the report immediately
      handleDownload(newReport.id, newReport.downloadUrl);

      await fetchData();
      setShowCreateModal(false);
      resetForm();

      alert('Report generated successfully!');
    } catch (err: any) {
      alert('Error: ' + err.message);
    } finally {
      setGenerating(false);
    }
  };

  const handleDownload = async (reportId: string, downloadUrl: string) => {
    try {
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/reports/${reportId}/download`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (!response.ok) throw new Error('Failed to download report');

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = downloadUrl.split('/').pop() || 'report';
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
    } catch (err: any) {
      alert('Error downloading report: ' + err.message);
    }
  };

  const handleDeleteReport = async (id: string) => {
    if (!confirm('Are you sure you want to delete this report?')) return;

    try {
      const token = localStorage.getItem('vulnx_token');
      const response = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000'}/reports/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (!response.ok) throw new Error('Failed to delete report');

      await fetchData();
    } catch (err: any) {
      alert('Error: ' + err.message);
    }
  };

  const resetForm = () => {
    setReportTitle('');
    setSelectedFormat('PDF');
    setSelectedTargets([]);
    setIncludeVulns(true);
    setIncludeScans(true);
    setIncludeRecommendations(true);
  };

  const toggleTarget = (targetId: string) => {
    setSelectedTargets(prev => 
      prev.includes(targetId)
        ? prev.filter(id => id !== targetId)
        : [...prev, targetId]
    );
  };

  const getFormatIcon = (format: string) => {
    switch (format) {
      case 'PDF': return <File className="w-4 h-4 text-cyber-pink" />;
      case 'MARKDOWN': return <FileCode className="w-4 h-4 text-cyber-blue" />;
      case 'JSON': return <FileJson className="w-4 h-4 text-cyber-green" />;
      default: return <FileText className="w-4 h-4" />;
    }
  };

  const getFormatColor = (format: string) => {
    switch (format) {
      case 'PDF': return 'bg-cyber-pink/10 text-cyber-pink border-cyber-pink/20';
      case 'MARKDOWN': return 'bg-cyber-blue/10 text-cyber-blue border-cyber-blue/20';
      case 'JSON': return 'bg-cyber-green/10 text-cyber-green border-cyber-green/20';
      default: return 'bg-cyber-muted/10 text-cyber-muted border-cyber-muted/20';
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#050812]">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-cyber-green border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-cyber-green font-mono text-sm">Loading Reports...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#050812] text-white p-6">
      {/* Header */}
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <div>
            <h1 className="text-3xl font-heading font-bold text-white mb-2">
              Security Reports
            </h1>
            <p className="text-cyber-muted font-mono text-sm">
              Generate comprehensive security reports in PDF, Markdown, or JSON format
            </p>
          </div>

          <div className="flex gap-3">
            <button
              onClick={fetchData}
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors flex items-center gap-2"
            >
              <RefreshCcw className="w-4 h-4" />
              Refresh
            </button>

            <button
              onClick={() => setShowCreateModal(true)}
              className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors flex items-center gap-2"
            >
              <Plus className="w-4 h-4" />
              Generate Report
            </button>

            <Link
              href="/dashboard"
              className="px-4 py-2 bg-[#0b1120] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors"
            >
              Back to Dashboard
            </Link>
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Total Reports</p>
          <p className="text-2xl font-heading font-bold text-white">{reports.length}</p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">PDF Reports</p>
          <p className="text-2xl font-heading font-bold text-cyber-pink">
            {reports.filter(r => r.format === 'PDF').length}
          </p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">Markdown</p>
          <p className="text-2xl font-heading font-bold text-cyber-blue">
            {reports.filter(r => r.format === 'MARKDOWN').length}
          </p>
        </div>
        <div className="bg-[#0b1120] border border-white/5 p-4 rounded-sm">
          <p className="text-cyber-muted font-mono text-xs uppercase mb-2">JSON</p>
          <p className="text-2xl font-heading font-bold text-cyber-green">
            {reports.filter(r => r.format === 'JSON').length}
          </p>
        </div>
      </div>

      {/* Reports List */}
      <div className="bg-[#0b1120] border border-white/5 rounded-sm overflow-hidden">
        <div className="p-4 border-b border-white/5">
          <h2 className="text-lg font-heading font-bold text-white">Generated Reports</h2>
        </div>

        {reports.length === 0 ? (
          <div className="p-12 text-center">
            <FileText className="w-16 h-16 text-cyber-muted mx-auto mb-4" />
            <p className="text-cyber-muted font-mono text-sm mb-4">No reports generated yet</p>
            <button
              onClick={() => setShowCreateModal(true)}
              className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm"
            >
              Generate Your First Report
            </button>
          </div>
        ) : (
          <div className="divide-y divide-white/5">
            {reports.map((report) => (
              <div key={report.id} className="p-4 hover:bg-white/[0.02] transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4 flex-1">
                    <div className="p-3 bg-cyber-green/10 rounded-sm">
                      {getFormatIcon(report.format)}
                    </div>

                    <div className="flex-1">
                      <div className="flex items-center gap-3 mb-1">
                        <h3 className="text-white font-heading font-bold text-base">
                          {report.title}
                        </h3>
                        <span className={`px-2 py-0.5 rounded-sm text-xs font-mono font-bold border ${getFormatColor(report.format)}`}>
                          {report.format}
                        </span>
                      </div>

                      <div className="flex items-center gap-4 text-xs font-mono text-cyber-muted">
                        <span className="flex items-center gap-1">
                          <Calendar className="w-3 h-3" />
                          {new Date(report.createdAt).toLocaleString()}
                        </span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => handleDownload(report.id, report.downloadUrl)}
                      className="p-2 rounded-sm border border-cyber-green/20 text-cyber-green hover:bg-cyber-green/10 transition-colors"
                      title="Download"
                    >
                      <Download className="w-4 h-4" />
                    </button>

                    <button
                      onClick={() => handleDeleteReport(report.id)}
                      className="p-2 rounded-sm border border-cyber-pink/20 text-cyber-pink hover:bg-cyber-pink/10 transition-colors"
                      title="Delete"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Create Modal */}
      {showCreateModal && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-6">
          <div className="bg-[#0b1120] border border-white/10 rounded-sm max-w-3xl w-full max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-white/5">
              <h2 className="text-xl font-heading font-bold text-white">Generate Security Report</h2>
            </div>

            <div className="p-6 space-y-6">
              {/* Report Title */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-2">
                  Report Title *
                </label>
                <input
                  type="text"
                  value={reportTitle}
                  onChange={(e) => setReportTitle(e.target.value)}
                  placeholder="e.g., Q4 2024 Security Assessment"
                  className="w-full bg-[#050812] border border-white/10 text-white font-mono text-sm px-4 py-3 rounded-sm focus:border-cyber-green outline-none"
                />
              </div>

              {/* Format Selection */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-3">
                  Report Format *
                </label>
                <div className="grid grid-cols-3 gap-3">
                  {(['PDF', 'MARKDOWN', 'JSON'] as const).map((format) => (
                    <button
                      key={format}
                      onClick={() => setSelectedFormat(format)}
                      className={`p-4 rounded-sm border transition-all ${
                        selectedFormat === format
                          ? 'border-cyber-green bg-cyber-green/10'
                          : 'border-white/10 bg-[#050812] hover:border-white/20'
                      }`}
                    >
                      <div className="flex flex-col items-center gap-2">
                        {getFormatIcon(format)}
                        <span className="text-white font-mono text-sm font-bold">{format}</span>
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Target Selection */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-3">
                  Select Targets * ({selectedTargets.length} selected)
                </label>
                <div className="max-h-48 overflow-y-auto space-y-2 bg-[#050812] border border-white/10 rounded-sm p-3">
                  {targets.map((target) => (
                    <label
                      key={target.id}
                      className="flex items-center gap-3 p-2 hover:bg-white/[0.02] rounded-sm cursor-pointer transition-colors"
                    >
                      <input
                        type="checkbox"
                        checked={selectedTargets.includes(target.id)}
                        onChange={() => toggleTarget(target.id)}
                        className="w-4 h-4"
                      />
                      <div className="flex-1">
                        <p className="text-white font-mono text-sm">{target.name}</p>
                        <p className="text-cyber-muted font-mono text-xs">{target.scope}</p>
                      </div>
                    </label>
                  ))}
                </div>
              </div>

              {/* Report Options */}
              <div>
                <label className="block text-sm font-mono text-cyber-muted mb-3">
                  Report Contents
                </label>
                <div className="space-y-2">
                  <label className="flex items-center gap-3 p-3 bg-[#050812] border border-white/10 rounded-sm cursor-pointer hover:border-cyber-green/30 transition-colors">
                    <input
                      type="checkbox"
                      checked={includeVulns}
                      onChange={(e) => setIncludeVulns(e.target.checked)}
                      className="w-4 h-4"
                    />
                    <span className="text-white font-mono text-sm">Include Vulnerabilities</span>
                  </label>

                  <label className="flex items-center gap-3 p-3 bg-[#050812] border border-white/10 rounded-sm cursor-pointer hover:border-cyber-green/30 transition-colors">
                    <input
                      type="checkbox"
                      checked={includeScans}
                      onChange={(e) => setIncludeScans(e.target.checked)}
                      className="w-4 h-4"
                    />
                    <span className="text-white font-mono text-sm">Include Scan History</span>
                  </label>

                  <label className="flex items-center gap-3 p-3 bg-[#050812] border border-white/10 rounded-sm cursor-pointer hover:border-cyber-green/30 transition-colors">
                    <input
                      type="checkbox"
                      checked={includeRecommendations}
                      onChange={(e) => setIncludeRecommendations(e.target.checked)}
                      className="w-4 h-4"
                    />
                    <span className="text-white font-mono text-sm">Include Recommendations</span>
                  </label>
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-white/5 flex justify-end gap-3">
              <button
                onClick={() => {
                  setShowCreateModal(false);
                  resetForm();
                }}
                disabled={generating}
                className="px-4 py-2 bg-[#050812] border border-white/10 text-cyber-muted hover:text-white font-mono text-xs rounded-sm transition-colors disabled:opacity-50"
              >
                Cancel
              </button>
              <button
                onClick={handleGenerateReport}
                disabled={generating}
                className="px-4 py-2 bg-cyber-green text-black font-heading font-bold text-xs uppercase rounded-sm hover:bg-cyber-green/90 transition-colors disabled:opacity-50 flex items-center gap-2"
              >
                {generating ? (
                  <>
                    <Clock className="w-4 h-4 animate-spin" />
                    Generating...
                  </>
                ) : (
                  <>
                    <FileText className="w-4 h-4" />
                    Generate Report
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
